def semi_markov_q_learning(
    episodes: list,
    n_states: int,
    n_actions: int,
    gamma: float,
    alpha: float
) -> list:
    # Initialize Q-table to zeros
    Q = [[0.0] * n_actions for _ in range(n_states)]

    for episode in episodes:
        for (state, action, reward, next_state, duration, done) in episode:
            if done:
                target = reward
            else:
                # Key SMDP modification: discount by gamma^duration
                target = reward + (gamma ** duration) * max(Q[next_state])
            Q[state][action] += alpha * (target - Q[state][action])

    return [[round(q, 4) for q in row] for row in Q]

