import numpy as np

def semi_markov_q_learning(
    episodes: list,
    n_states: int,
    n_actions: int,
    gamma: float,
    alpha: float
) -> list:
    Q = np.zeros((n_states, n_actions), dtype=np.float64)

    for episode in episodes:
        for (state, action, reward, next_state, duration, done) in episode:
            if done:
                target = reward
            else:
                # gamma**duration scales discount by actual elapsed time
                target = reward + (gamma ** duration) * Q[next_state].max()
            Q[state, action] += alpha * (target - Q[state, action])

    return np.round(Q, 4).tolist()
